import boto3
import json
from typing import Dict, Any
import logging

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class SQSPublisher:
    def __init__(self, queue_url: str, region_name: str = 'us-east-1'):
        """
        Initialize SQS publisher with queue URL and region
        """
        self.queue_url = queue_url
        self.sqs_client = boto3.client('sqs', region_name=region_name)
        
    def send_user_data_message(self, user_data: Dict[str, Any]) -> Dict[str, Any]:
        """
        Send user data message to SQS queue
        """
        try:
            # Validate PII data presence
            if not self._validate_pii_data(user_data):
                logger.warning("PII data validation failed")
                return {"error": "PII data validation failed"}
            
            # Prepare message
            message_body = json.dumps(user_data, ensure_ascii=False)
            
            # Send message to SQS
            response = self.sqs_client.send_message(
                QueueUrl=self.queue_url,
                Message=message_body,
                MessageAttributes={
                    'MessageType': {
                        'StringValue': 'UserUserData',
                        'DataType': 'String'
                    }
                }
            )
            
            logger.info(f"Message sent successfully. MessageId: {response['MessageId']}")
            return response
            
        except Exception as e:
            logger.error(f"Failed to send message: {str(e)}")
            raise
    
    def _validate_pii_data(self, user_data: Dict[str, Any]) -> bool:
        """
        Validate that PII data is present in the message
        """
        required_fields = ['email', 'phone', 'address']
        for field in required_fields:
            if field not in user_data or not user_data[field]:
                logger.warning(f"Missing required PII field: {field}")
                return False
        return True

# Example usage
if __name__ == "__main__":
    # Configuration
    QUEUE_URL = "https://sqs.us-east-1.amazonaws.com/123456789012/user-data-queue"
    
